INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('optician-moex-02819', 'optician', 'optician-moex-106-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '有關遠方自覺式驗光的紅綠測試法，下列敘述何者正確？', '["受測者表示紅色清楚時，代表需在受測者眼前增加正的球面度數", "一般而言，矯正不足的近視眼會感覺綠色視標較清楚", "此測試的原理是由於單色光的波長不同，在眼底的成像位置亦不同，藉此來判斷受測者的屈光矯正狀態", "受測者表示紅綠一樣清楚時，此時代表紅、綠色光同時成像在視網膜上"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "6910876e629c", "answer_pdf_sha1": "a39ff037594a", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 44, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02820', 'optician', 'optician-moex-106-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '下列關於鐘面圖（clock dial test）檢查的敘述，何者正確？', '["應先將患者霧視，若患者表示2點與8點的線最清楚，則負圓柱透鏡的軸度應放置於30度位置", "應先將患者霧視，若患者表示2點與8點的線最清楚，則負圓柱透鏡的軸度應放置於60度位置", "無需將患者霧視，若患者表示2點與8點的線最清楚，則負圓柱透鏡的軸度應放置於30度位置", "無需將患者霧視，若患者表示2點與8點的線最清楚，則負圓柱透鏡的軸度應放置於60度位置"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "6910876e629c", "answer_pdf_sha1": "a39ff037594a", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 45, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02821', 'optician', 'optician-moex-106-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '當進行傑克森交叉圓柱鏡散光度檢查時，每次在調整0.50 DC後，要增加或減少0.25 DS之原因為何？', '["為了維持最小模糊圈在視網膜平面上", "為了維持等效球鏡度", "為了維持最佳稜鏡效果（prismatic effect）", "僅"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "6910876e629c", "answer_pdf_sha1": "a39ff037594a", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 46, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02822', 'optician', 'optician-moex-106-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '有關加正度數鏡片來達到霧視的敘述，下列何者錯誤？', '["在測量遠用視力時能有效放鬆眼睛的調節", "能有效確認所測量之度數沒有過於負（over-minus）", "常用的霧視方式包括加入+1.00 DS的球面透鏡片讓視力降至約0.5（20/40）左右", "霧視時成像在視網膜之後，因此任何調節可以讓影像更清晰"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "6910876e629c", "answer_pdf_sha1": "a39ff037594a", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 47, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02823', 'optician', 'optician-moex-106-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '老花眼者喜歡在較亮光照明下閱讀，主要是因為下列何種原理？', '["針孔原理", "近距離反射（near reflex）", "融像內聚（fusional convergence）", "生理性調節（physiological accommodation）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "6910876e629c", "answer_pdf_sha1": "a39ff037594a", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 48, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02824', 'optician', 'optician-moex-106-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '矯正老花眼的眼鏡片不包含下列何者？', '["正鏡片", "偏光鏡片", "雙焦鏡片", "漸進多焦點鏡片"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "6910876e629c", "answer_pdf_sha1": "a39ff037594a", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 49, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02825', 'optician', 'optician-moex-106-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '下列選項何者不能作為自覺式驗光時使用之裂隙鏡片的裂隙寬度？', '["0.5 mm", "0.75 mm", "1.0 mm", "2.5 mm"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "6910876e629c", "answer_pdf_sha1": "a39ff037594a", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 50, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optometrist-moex-00001', 'optometrist', 'optometrist-moex-114-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '下列有關史耐倫視力表（Snellenchart）、視標的敘述，何者錯誤？', '["在史耐倫視力表中，史耐倫分數（例如 20/40）的定義是指受試者從特定的距離觀看標準化字母或視力 檢查表，所測得的距離／字母大小", "在史耐倫視力表中，40英呎的標準化字母（40-ft字母）是指當從40英呎的距離觀看時，字母大小會占 視網膜的1分弧度，約為19.84公厘高", "假使一個人從10英呎的距離可以讀出的最小字母為15-ft，視力可記錄為20/30", "近距離的視力測量中，1M字體大約是8號字體，約1.45公厘高"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "5093f492e448", "answer_pdf_sha1": "f33d754e2a74", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "109", "s": "0905", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00002', 'optometrist', 'optometrist-moex-114-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '有關低視力視覺損傷者之敘述，下列何者錯誤？', '["低視力者的視野損傷，可能造成行走活動及閱讀的限制", "低視力者的視力低弱，藉由眼鏡完全矯正，視力仍無法滿足患者的需要", "任何患有影響視覺系統的疾病或障礙的低視力者，可能限制影響其生活功能", "許多低視力者認為少用殘餘視力（residualvision）對其眼睛較有幫助，所以盡量不用眼"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "5093f492e448", "answer_pdf_sha1": "f33d754e2a74", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "109", "s": "0905", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00003', 'optometrist', 'optometrist-moex-114-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '低視能患者因為視力較差，在閱讀時常需要使用輔具將字體放大。下列有關放大倍率及輔具選擇的敘述， 何者錯誤？', '["一個視力20/100的低視能患者，根據Ketenbaum法則的計算，需要至少+5.00屈光度的放大輔具", "考慮實質上的視覺保留度（substantialacuityreserve），要維持閱讀的舒適與流暢，建議字體要達到為所 能閱讀的最小字體2至5倍大 D", "因為有時不確定製造商是使用相對倍率的公式（M= ，M：放大倍率，D：鏡片的屈光度），還是製造 4 D 商的放大倍率公式（M= 1）來製造放大鏡；臨床上較喜歡使用鏡片的「屈光度」而非「倍率」來計 4 算、預測放大鏡的作用", "關於放大鏡的放大倍率，「相對倍率」的定義是將由放大鏡所看到的影像，與放置在一公尺遠的物體大 小做比較"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "5093f492e448", "answer_pdf_sha1": "f33d754e2a74", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "109", "s": "0905", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL)
